class Solution {
    private void deepLSum(Node root, int[] maxLevel, int curLevel, int[] ans) {
        if (root == null) return;
        if (curLevel > maxLevel[0]) {
            ans[0] = root.val;
            maxLevel[0] = curLevel;
        } else if (curLevel == maxLevel[0]) {
            ans[0] += root.val;
        }
        deepLSum(root.left, maxLevel, curLevel + 1, ans);
        deepLSum(root.right, maxLevel, curLevel + 1, ans);
    }

    // Public method to initiate calculation
    public int deepestLeavesSum(Node root) {
        int[] maxLevel = {0};  // Array used to mimic pass-by-reference
        int[] ans = {0};  // Array used to mimic pass-by-reference
        deepLSum(root, maxLevel, 0, ans);
        return ans[0];
    }
}

