function sumDeepestLeaves(root) {
    if (!root) return 0;

    let queue = [root];
    let sum = 0;

    while (queue.length > 0) {
        let levelSum = 0;
        let size = queue.length;

        for (let i = 0; i < size; i++) {
            let node = queue.shift();

            if (!node.left && !node.right) {
                levelSum += node.val;
            }

            if (node.left) {
                queue.push(node.left);
            }
            if (node.right) {
                queue.push(node.right);
            }
        }

        if (queue.length === 0) {
            sum = levelSum; 
        }
    }

    return sum;
}
